import base64
import json
import hashlib
import sys

def compute_seal(payloads):
    h = hashlib.sha3_256()
    for k in sorted(payloads.keys()):
        h.update(k.encode('utf-8'))
        h.update(payloads[k].encode('utf-8'))
    return "996.1-ARKHE-ONCHAIN-" + h.hexdigest()[:16].upper()

def main():
    payloads = {
        "axiarchy_gate.aml": "",
        "substrate.toml": "",
        "README.md": "",
        "Makefile": "",
        "docs/DEPLOY.md": "",
        "programs/axiarchy_gate.aml": "",
        "programs/theosis_registry.aml": "",
        "programs/temporal_anchor.aml": "",
        "programs/passport_gateway.aml": "",
        "programs/bindu_coherence.aml": "",
        "programs/substrate_catalog.aml": "",
        "programs/omniscient_solver.aml": "",
        "programs/interfaces/IAxiarchyGate.aml": "",
        "programs/interfaces/ITheosisRegistry.aml": "",
        "programs/interfaces/ITemporalAnchor.aml": "",
        "programs/interfaces/IPassportGateway.aml": "",
        "programs/interfaces/IBinduCoherence.aml": "",
        "programs/interfaces/ISubstrateCatalog.aml": "",
        "programs/interfaces/IOmniscientSolver.aml": "",
        "bridge/arkhe-octra-bridge/Cargo.toml": "",
        "bridge/arkhe-octra-bridge/src/main.rs": "",
    }

    seal = compute_seal(payloads)

    report = {
        "Substrate_ID": "996.1",
        "Name": "ARKHE-ONCHAIN (Octra Bridge)",
        "Type": "Canonizer",
        "Status": "Canonized",
        "Architect_ORCID": "0009-0005-2697-4668",
        "Odometer": "∞.Ω.∇+++.996.1",
        "Files": [{"filename": k, "content": v} for k, v in payloads.items()],
        "Canonical_Seal": seal
    }

    print(json.dumps(report, indent=2))

if __name__ == "__main__":
    main()
